package main

import (
	"html/template"
	"log"
	"net/http"
)

type Comment struct {
	Author  string
	Content template.HTML
}

var comments = []Comment{
	{
		Author:  "Alice",
		Content: template.HTML("Hello, <b>world</b>!"),
	},
	{
		Author:  "Bob",
		Content: template.HTML("Nice post!<br><i>Thanks for sharing.</i>"),
	},
	{
		Author:  "Charlie",
		Content: template.HTML(`Check this out: <a href="https://example.com">example</a>`),
	},
}

var pageTmpl = template.Must(template.New("comments").Parse(`
<!DOCTYPE html>
<html lang="en">
<head>
	<meta charset="UTF-8">
	<meta name="viewport" content="width=device-width, initial-scale=1.0">
	<title>Comments</title>
</head>
<body>
	<h1>User Comments</h1>
	<ul>
		{{range .}}
		<li>
			<strong>{{.Author}}</strong>: {{.Content}}
		</li>
		{{else}}
		<li>No comments yet.</li>
		{{end}}
	</ul>
</body>
</html>
`))

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	if err := pageTmpl.Execute(w, comments); err != nil {
		http.Error(w, "failed to render comments", http.StatusInternalServerError)
		return
	}
}

func main() {
	http.HandleFunc("/", commentsHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}